`,o.jsx(n.p,{children:"This litepaper provides a high-level view. The full privacy model defines threat assumptions, adversaries, mitigations, and compliance modes."}),`
`,o.jsxs(n.ul,{children:[`
`,o.jsx(n.li,{children:"Goals: conceal participant identity and intent while keeping claims and settlement verifiable."}),`
`,o.jsx(n.li,{children:"Mechanisms: selective disclosure proofs, sealed-bid auctions, and relayer-based execution."}),`
`,o.jsx(n.li,{children:"Constraints: on-chain data remains public; privacy is opt-in and policy-driven per pool."}),`
`,o.jsxs(n.li,{children:["Details: see ",o.jsx(n.code,{children:"docs/PRIVACY_MODEL.md"})," and ",o.jsx(n.code,{children:"docs/TECHNICAL_SPEC.md"}),"."]}),`
