`,o.jsx(n.p,{children:"Unlock events can concentrate sell pressure. The auction primitive reduces that pressure by shifting early exit demand away from spot markets and into discounted claim-right sales:"}),`
`,o.jsxs(n.ul,{children:[`
`,o.jsx(n.li,{children:"Users who would otherwise dump can sell claim rights ahead of unlock at a known discount."}),`
`,o.jsx(n.li,{children:"Buyers are long-horizon holders (including the protocol treasury) rather than short-term sellers."}),`
