`,o.jsx(n.h2,{children:"Is this custodial?"}),`
`,o.jsx(n.p,{children:"No. Users keep wallet control. The protocol only escrows claim rights."}),`
`,o.jsx(n.h2,{children:"Are there margin calls?"}),`
`,o.jsx(n.p,{children:"No. Settlement happens at unlock time based on repayment status."}),`
